<template><div class="page-container narrow"><PageHeader eyebrow="INBOX" title="通知中心" :description="`当前有 ${unread} 条未读通知`"><el-button @click="readAll">全部标记已读</el-button></PageHeader><div v-loading="loading" class="notice-list"><article v-for="n in page.list" :key="n.userMessageId" :class="['notice-item',{unread:n.readStatus===0}]"><div class="notice-dot"></div><div class="notice-body"><div class="notice-head"><h3>{{ n.title }}</h3><span>{{ formatDate(n.createdAt) }}</span></div><p>{{ n.content }}</p><div class="tag-row"><el-tag size="small">{{ n.noticeType||'SYSTEM' }}</el-tag><el-tag v-if="n.targetType" size="small" effect="plain">{{ n.targetType }} #{{ n.targetId }}</el-tag></div></div><div class="notice-actions"><el-button v-if="n.readStatus===0" text type="primary" @click="markRead(n)">标记已读</el-button><el-button text type="danger" @click="remove(n)">删除</el-button></div></article><EmptyState v-if="!loading&&!page.list.length" description="暂无通知"/></div><div class="pagination-wrap"><el-pagination background :total="page.total" :page-size="size" v-model:current-page="current" @current-change="load"/></div></div></template>
<script setup>import { onMounted,reactive,ref } from 'vue';import PageHeader from '../../components/PageHeader.vue';import EmptyState from '../../components/EmptyState.vue';import { notificationApi } from '../../api/notification';import { normalizePage } from '../../utils/page';import { formatDate } from '../../utils/format';const loading=ref(false),unread=ref(0),current=ref(1),size=10,page=reactive({list:[],total:0});async function load(){loading.value=true;try{Object.assign(page,normalizePage(await notificationApi.mine({page:current.value-1,size})));unread.value=await notificationApi.unreadCount()}finally{loading.value=false}}async function markRead(n){await notificationApi.read(n.userMessageId);n.readStatus=1;unread.value=Math.max(0,unread.value-1)}async function readAll(){await notificationApi.readAll();page.list.forEach(n=>n.readStatus=1);unread.value=0}async function remove(n){await notificationApi.remove(n.userMessageId);load()}onMounted(load)</script>
